import { useMemo } from 'react';
import { Button } from '@/components/ui/button';
import { supabase } from '@/integrations/supabase/client';
import { useToast } from '@/hooks/use-toast';
import type { Database } from '@/integrations/supabase/types';

type AuctionPlayer = Database['public']['Tables']['auction_players']['Row'];

interface Props {
  auctionPlayers: AuctionPlayer[];
  onComplete: () => void;
}

export function AcceleratedAuction({ auctionPlayers, onComplete }: Props) {
  const { toast } = useToast();

  const unsoldPlayers = useMemo(() =>
    auctionPlayers.filter(p => p.status === 'unsold'),
    [auctionPlayers]
  );

  const setAsCurrent = async (playerId: string) => {
    // Clear any current player first
    await supabase.from('auction_players').update({
      status: 'available', current_bid: null, leading_team_id: null
    } as any).eq('status', 'current');

    const player = auctionPlayers.find(p => p.id === playerId);
    const baseCr = player ? player.base_price / 100 : 0;
    await supabase.from('auction_players').update({
      status: 'current', current_bid: baseCr, leading_team_id: null
    } as any).eq('id', playerId);

    toast({ title: `${player?.player_name} set for accelerated auction` });
    onComplete();
  };

  if (unsoldPlayers.length === 0) return null;

  return (
    <div className="bg-card border border-border rounded-lg p-3">
      <div className="flex items-center justify-between mb-2">
        <h3 className="font-display font-bold text-sm text-foreground">
          ΓÜí Accelerated Auction
        </h3>
        <span className="text-[10px] bg-unsold/20 text-unsold px-1.5 py-0.5 rounded font-medium">
          {unsoldPlayers.length} unsold
        </span>
      </div>
      <div className="space-y-1 max-h-[200px] overflow-y-auto scrollbar-thin">
        {unsoldPlayers.map(p => (
          <div key={p.id} className="flex items-center justify-between text-xs py-1.5 px-2 rounded bg-muted/20 hover:bg-muted/40">
            <div>
              <span className="font-medium text-foreground">{p.player_name}</span>
              <span className="text-muted-foreground ml-1.5">{p.role} ┬╖ Γé╣{p.base_price}L</span>
            </div>
            <Button size="sm" variant="ghost" className="h-6 text-[10px] px-2" onClick={() => setAsCurrent(p.id)}>
              Re-Auction
            </Button>
          </div>
        ))}
      </div>
    </div>
  );
}

import { useState, useRef } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Switch } from '@/components/ui/switch';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from '@/components/ui/dialog';
import { useToast } from '@/hooks/use-toast';
import { Loader2, Upload, X } from 'lucide-react';

interface Props {
  onAdded: () => void;
}

export function AddPlayerModal({ onAdded }: Props) {
  const { toast } = useToast();
  const [open, setOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [imageFile, setImageFile] = useState<File | null>(null);
  const [imagePreview, setImagePreview] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [form, setForm] = useState({
    player_name: '',
    country: 'India',
    age: '',
    role: '',
    batting_style: '',
    bowling_style: '',
    base_price: '',
    set_number: '',
    set_name: '',
    ipl_caps: '',
    is_capped: false,
  });

  const update = (key: string, value: any) => setForm(f => ({ ...f, [key]: value }));

  const handleImageSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    if (file.size > 5 * 1024 * 1024) {
      toast({ title: 'Image must be under 5MB', variant: 'destructive' });
      return;
    }
    setImageFile(file);
    setImagePreview(URL.createObjectURL(file));
  };

  const clearImage = () => {
    setImageFile(null);
    setImagePreview(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const uploadImage = async (playerName: string): Promise<string | null> => {
    if (!imageFile) return null;
    const ext = imageFile.name.split('.').pop() || 'jpg';
    const path = `${Date.now()}-${playerName.replace(/\s+/g, '_')}.${ext}`;
    const { error } = await supabase.storage.from('player-images').upload(path, imageFile);
    if (error) {
      console.error('Upload error:', error);
      return null;
    }
    const { data } = supabase.storage.from('player-images').getPublicUrl(path);
    return data.publicUrl;
  };

  const handleSubmit = async () => {
    if (!form.player_name.trim()) {
      toast({ title: 'Player name is required', variant: 'destructive' });
      return;
    }
    if (!form.role) {
      toast({ title: 'Role is required', variant: 'destructive' });
      return;
    }
    if (!form.base_price || isNaN(parseInt(form.base_price))) {
      toast({ title: 'Valid base price is required', variant: 'destructive' });
      return;
    }

    setLoading(true);
    try {
      const imageUrl = await uploadImage(form.player_name.trim());

      const { error } = await supabase.from('auction_players').insert({
        player_name: form.player_name.trim(),
        country: form.country || 'India',
        age: form.age ? parseInt(form.age) : null,
        role: form.role,
        batting_style: form.batting_style || null,
        bowling_style: form.bowling_style || null,
        base_price: parseInt(form.base_price),
        set_number: form.set_number ? parseInt(form.set_number) : null,
        set_name: form.set_name || null,
        ipl_caps: form.ipl_caps ? parseInt(form.ipl_caps) : 0,
        is_capped: form.is_capped,
        status: 'available',
        image_url: imageUrl,
      });

      if (error) {
        console.error('Supabase insert error:', error);
        toast({ title: 'Failed to add player', description: error.message, variant: 'destructive' });
        return;
      }

      toast({ title: `Γ£à ${form.player_name} added to auction list` });
      setForm({
        player_name: '', country: 'India', age: '', role: '', batting_style: '',
        bowling_style: '', base_price: '', set_number: '', set_name: '', ipl_caps: '', is_capped: false,
      });
      clearImage();
      setOpen(false);
      onAdded();
    } catch (err: any) {
      console.error('Unexpected error:', err);
      toast({ title: 'Unexpected error', description: err?.message || 'Please try again', variant: 'destructive' });
    } finally {
      setLoading(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        <Button variant="outline" size="sm" className="text-xs">+ Add New Player</Button>
      </DialogTrigger>
      <DialogContent className="max-w-md max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle className="font-display">Add New Player</DialogTitle>
        </DialogHeader>
        <div className="space-y-3">
          {/* Photo Upload */}
          <div>
            <label className="text-xs text-muted-foreground">Player Photo</label>
            <div className="mt-1">
              {imagePreview ? (
                <div className="relative w-24 h-24">
                  <img src={imagePreview} alt="Preview" className="w-24 h-24 rounded-lg object-cover border border-border" />
                  <button
                    type="button"
                    onClick={clearImage}
                    className="absolute -top-2 -right-2 w-5 h-5 rounded-full bg-destructive text-destructive-foreground flex items-center justify-center"
                  >
                    <X className="w-3 h-3" />
                  </button>
                </div>
              ) : (
                <button
                  type="button"
                  onClick={() => fileInputRef.current?.click()}
                  className="w-24 h-24 rounded-lg border-2 border-dashed border-border hover:border-primary/50 flex flex-col items-center justify-center gap-1 text-muted-foreground hover:text-primary transition-colors"
                >
                  <Upload className="w-5 h-5" />
                  <span className="text-[10px]">Upload</span>
                </button>
              )}
              <input
                ref={fileInputRef}
                type="file"
                accept="image/*"
                onChange={handleImageSelect}
                className="hidden"
              />
            </div>
          </div>

          <div>
            <label className="text-xs text-muted-foreground">Player Name *</label>
            <Input value={form.player_name} onChange={e => update('player_name', e.target.value)} placeholder="Player name" className="h-8 text-sm" />
          </div>
          <div className="grid grid-cols-2 gap-2">
            <div>
              <label className="text-xs text-muted-foreground">Country</label>
              <Input value={form.country} onChange={e => update('country', e.target.value)} placeholder="Country" className="h-8 text-sm" />
            </div>
            <div>
              <label className="text-xs text-muted-foreground">Age</label>
              <Input type="number" value={form.age} onChange={e => update('age', e.target.value)} placeholder="Age" className="h-8 text-sm" />
            </div>
          </div>
          <div className="grid grid-cols-2 gap-2">
            <div>
              <label className="text-xs text-muted-foreground">Role *</label>
              <Select value={form.role} onValueChange={v => update('role', v)}>
                <SelectTrigger className="h-8 text-xs"><SelectValue placeholder="Select role" /></SelectTrigger>
                <SelectContent>
                  <SelectItem value="BATTER">Batter</SelectItem>
                  <SelectItem value="BOWLER">Bowler</SelectItem>
                  <SelectItem value="ALL-ROUNDER">All-Rounder</SelectItem>
                  <SelectItem value="WICKETKEEPER">Wicketkeeper</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div>
              <label className="text-xs text-muted-foreground">Base Price (Γé╣ Lakh) *</label>
              <Input type="number" value={form.base_price} onChange={e => update('base_price', e.target.value)} placeholder="e.g. 200" className="h-8 text-sm" />
            </div>
          </div>
          <div className="grid grid-cols-2 gap-2">
            <div>
              <label className="text-xs text-muted-foreground">Set Number</label>
              <Input type="number" value={form.set_number} onChange={e => update('set_number', e.target.value)} placeholder="e.g. 1" className="h-8 text-sm" />
            </div>
            <div>
              <label className="text-xs text-muted-foreground">Set Name</label>
              <Input value={form.set_name} onChange={e => update('set_name', e.target.value)} placeholder="e.g. Marquee" className="h-8 text-sm" />
            </div>
          </div>
          <div className="grid grid-cols-2 gap-2">
            <div>
              <label className="text-xs text-muted-foreground">Batting Style</label>
              <Input value={form.batting_style} onChange={e => update('batting_style', e.target.value)} placeholder="e.g. RHB" className="h-8 text-sm" />
            </div>
            <div>
              <label className="text-xs text-muted-foreground">Bowling Style</label>
              <Input value={form.bowling_style} onChange={e => update('bowling_style', e.target.value)} placeholder="e.g. Right Arm Fast" className="h-8 text-sm" />
            </div>
          </div>
          <div className="grid grid-cols-2 gap-2">
            <div>
              <label className="text-xs text-muted-foreground">IPL Caps</label>
              <Input type="number" value={form.ipl_caps} onChange={e => update('ipl_caps', e.target.value)} placeholder="0" className="h-8 text-sm" />
            </div>
            <div className="flex items-center gap-2 mt-4">
              <Switch checked={form.is_capped} onCheckedChange={v => update('is_capped', v)} />
              <label className="text-xs text-muted-foreground">Capped Player</label>
            </div>
          </div>
          <div className="flex gap-2 pt-2">
            <Button onClick={handleSubmit} className="flex-1" disabled={loading}>
              {loading && <Loader2 className="w-3 h-3 mr-1 animate-spin" />}
              Add Player
            </Button>
            <Button variant="outline" onClick={() => setOpen(false)} className="flex-1">Cancel</Button>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}

import { useState, useCallback, useRef } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { Button } from '@/components/ui/button';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { useToast } from '@/hooks/use-toast';
import { AuctionTimer, AuctionTimerHandle } from '@/components/AuctionTimer';
import type { Database } from '@/integrations/supabase/types';

function playSoldSound() {
  const ctx = new AudioContext();
  const hit = ctx.createOscillator();
  const hitGain = ctx.createGain();
  hit.type = 'square';
  hit.frequency.setValueAtTime(200, ctx.currentTime);
  hit.frequency.exponentialRampToValueAtTime(80, ctx.currentTime + 0.15);
  hitGain.gain.setValueAtTime(0.6, ctx.currentTime);
  hitGain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.2);
  hit.connect(hitGain).connect(ctx.destination);
  hit.start(ctx.currentTime);
  hit.stop(ctx.currentTime + 0.2);

  const chime = ctx.createOscillator();
  const chimeGain = ctx.createGain();
  chime.type = 'sine';
  chime.frequency.setValueAtTime(523, ctx.currentTime + 0.25);
  chime.frequency.setValueAtTime(659, ctx.currentTime + 0.4);
  chime.frequency.setValueAtTime(784, ctx.currentTime + 0.55);
  chimeGain.gain.setValueAtTime(0.3, ctx.currentTime + 0.25);
  chimeGain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.9);
  chime.connect(chimeGain).connect(ctx.destination);
  chime.start(ctx.currentTime + 0.25);
  chime.stop(ctx.currentTime + 0.9);
}

type AuctionPlayer = Database['public']['Tables']['auction_players']['Row'];
type Team = Database['public']['Tables']['teams']['Row'];

interface Props {
  currentPlayer: AuctionPlayer;
  teams: Team[];
  onComplete: () => void;
}

const BID_INCREMENTS = [
  { label: '+5L', value: 0.05 },
  { label: '+10L', value: 0.10 },
  { label: '+20L', value: 0.20 },
  { label: '+25L', value: 0.25 },
  { label: '+50L', value: 0.50 },
  { label: '+1 Cr', value: 1.00 },
];

export function BidTracker({ currentPlayer, teams, onComplete }: Props) {
  const { toast } = useToast();
  const [selectedTeam, setSelectedTeam] = useState('');
  const [soldPrice, setSoldPrice] = useState('');
  const [timerExpired, setTimerExpired] = useState(false);
  const timerRef = useRef<AuctionTimerHandle>(null);

  const currentBid = (currentPlayer as any).current_bid as number | null;
  const leadingTeamId = (currentPlayer as any).leading_team_id as string | null;
  const basePriceCr = currentPlayer.base_price / 100;
  const displayBid = currentBid ?? basePriceCr;

  const leadingTeam = teams.find(t => t.id === leadingTeamId);

  const handleTimerEnd = useCallback(() => {
    setTimerExpired(true);
  }, []);

  const incrementBid = async (amount: number) => {
    if (timerExpired) return; // Freeze bids when timer expired
    const newBid = displayBid + amount;
    await supabase.from('auction_players').update({
      current_bid: newBid,
      leading_team_id: selectedTeam || leadingTeamId,
      timer_started_at: new Date().toISOString(),
    } as any).eq('id', currentPlayer.id);
    // Auto-start/reset timer on each bid
    setTimerExpired(false);
    timerRef.current?.start();
    onComplete();
  };

  const resetBid = async () => {
    await supabase.from('auction_players').update({
      current_bid: basePriceCr,
      leading_team_id: null,
      timer_started_at: null,
    } as any).eq('id', currentPlayer.id);
    setSelectedTeam('');
    setTimerExpired(false);
    timerRef.current?.reset();
    onComplete();
  };

  const confirmSale = async () => {
    const price = soldPrice ? parseFloat(soldPrice) : displayBid;
    const teamId = selectedTeam || leadingTeamId;
    if (!teamId || !price) {
      toast({ title: 'Select a team and ensure bid is set', variant: 'destructive' });
      return;
    }

    const team = teams.find(t => t.id === teamId);
    if (!team) return;

    await supabase.from('auction_players').update({
      status: 'sold',
      sold_to_team: teamId,
      sold_price: price,
      current_bid: null,
      leading_team_id: null,
    } as any).eq('id', currentPlayer.id);

    await supabase.from('teams').update({
      spent_budget: team.spent_budget + price,
    }).eq('id', teamId);

    await supabase.from('auction_log').insert({
      player_id: currentPlayer.id,
      team_id: teamId,
      player_name: currentPlayer.player_name,
      team_name: team.short_name,
      sold_price: price,
      action: 'sold',
    });

    setSoldPrice('');
    setSelectedTeam('');
    setTimerExpired(false);
    timerRef.current?.reset();
    playSoldSound();
    toast({ title: `${currentPlayer.player_name} sold to ${team.short_name} for Γé╣${price.toFixed(2)} Cr!` });
    onComplete();
  };

  const markUnsold = async () => {
    await supabase.from('auction_players').update({
      status: 'unsold',
      current_bid: null,
      leading_team_id: null,
    } as any).eq('id', currentPlayer.id);

    await supabase.from('auction_log').insert({
      player_id: currentPlayer.id,
      player_name: currentPlayer.player_name,
      action: 'unsold',
    });

    setTimerExpired(false);
    timerRef.current?.reset();
    toast({ title: `${currentPlayer.player_name} marked as unsold` });
    onComplete();
  };

  return (
    <div className="bg-card border border-border rounded-lg p-4 space-y-4">
      {/* Player Info */}
      <div>
        <div className="flex items-center gap-2 mb-2">
          <span className="w-2 h-2 rounded-full bg-live live-pulse" />
          <span className="text-xs font-bold text-live uppercase">Now Auctioning</span>
        </div>
        <h2 className="font-display font-bold text-xl text-foreground">{currentPlayer.player_name}</h2>
        <p className="text-xs text-muted-foreground">
          {currentPlayer.role} | {currentPlayer.country} | Base: Γé╣{currentPlayer.base_price >= 100 ? `${basePriceCr.toFixed(2)} Cr` : `${currentPlayer.base_price} L`}
        </p>
      </div>

      {/* Live Bid Tracker */}
      <div className="bg-muted/30 rounded-lg p-3 space-y-3">
        <div className="flex items-center justify-between">
          <div>
            <div className="text-xs text-muted-foreground">Current Bid</div>
            <div className="font-display font-bold text-2xl text-live">Γé╣{displayBid.toFixed(2)} Cr</div>
          </div>
          <div className="text-right">
            <div className="text-xs text-muted-foreground">Leading Bidder</div>
            <div className="font-display font-bold text-sm" style={leadingTeam ? { color: leadingTeam.color } : {}}>
              {leadingTeam ? leadingTeam.short_name : 'None'}
            </div>
          </div>
        </div>

        {/* Team selector for bid */}
        <Select value={selectedTeam} onValueChange={setSelectedTeam}>
          <SelectTrigger className={`h-8 text-xs ${timerExpired ? 'ring-2 ring-live animate-pulse' : ''}`}>
            <SelectValue placeholder={timerExpired ? 'ΓÜá∩╕Å Select bidding team!' : 'Select bidding team'} />
          </SelectTrigger>
          <SelectContent>
            {teams.map(t => (
              <SelectItem key={t.id} value={t.id}>
                {t.short_name} ΓÇö Γé╣{(t.total_budget - t.spent_budget).toFixed(2)} Cr left
              </SelectItem>
            ))}
          </SelectContent>
        </Select>

        {/* Bid Increment Buttons */}
        <div className="grid grid-cols-3 gap-2">
          {BID_INCREMENTS.map(inc => (
            <Button
              key={inc.label}
              size="sm"
              onClick={() => incrementBid(inc.value)}
              disabled={timerExpired}
              className={`h-10 font-bold text-sm ${
                timerExpired 
                  ? 'bg-muted text-muted-foreground cursor-not-allowed opacity-50' 
                  : 'bg-accent text-accent-foreground hover:bg-accent/80'
              }`}
            >
              {inc.label}
            </Button>
          ))}
        </div>

        <Button variant="outline" size="sm" className="w-full text-xs" onClick={resetBid}>
          Γå║ Reset Bid to Base
        </Button>

        {/* Auction Timer */}
        <AuctionTimer ref={timerRef} onTimerEnd={handleTimerEnd} />

        {timerExpired && (
          <div className="text-center text-xs font-bold text-live animate-pulse">
            ΓÅ░ Timer expired! Select a team and confirm the sale or mark unsold.
          </div>
        )}
      </div>

      {/* Confirm Sale */}
      <div className="space-y-2">
        <div>
          <label className="text-xs text-muted-foreground mb-1 block">Sold Price (auto-filled, editable)</label>
          <input
            type="number"
            step="0.05"
            min="0"
            value={soldPrice || displayBid.toFixed(2)}
            onChange={e => setSoldPrice(e.target.value)}
            className="flex h-9 w-full rounded-md border border-input bg-background px-3 py-1 text-sm ring-offset-background placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
          />
        </div>
        <div className="flex gap-2">
          <Button onClick={confirmSale} className="flex-1">Γ£à Confirm Sale</Button>
          <Button variant="outline" onClick={markUnsold} className="flex-1">Γ¥î Unsold</Button>
        </div>
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { supabase } from '@/integrations/supabase/client';
import type { Database } from '@/integrations/supabase/types';

type AuctionPlayer = Database['public']['Tables']['auction_players']['Row'];
type Team = Database['public']['Tables']['teams']['Row'];

interface Props {
  player: AuctionPlayer | null;
  teams?: Team[];
  fullscreen?: boolean;
}

function playTickSound() {
  try {
    const ctx = new AudioContext();
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.type = 'sine';
    osc.frequency.setValueAtTime(800, ctx.currentTime);
    gain.gain.setValueAtTime(0.15, ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.1);
    osc.connect(gain).connect(ctx.destination);
    osc.start(ctx.currentTime);
    osc.stop(ctx.currentTime + 0.1);
  } catch {}
}

function playTimerEndSound() {
  try {
    const ctx = new AudioContext();
    [0, 0.15, 0.3].forEach(offset => {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = 'square';
      osc.frequency.setValueAtTime(1000, ctx.currentTime + offset);
      gain.gain.setValueAtTime(0.3, ctx.currentTime + offset);
      gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + offset + 0.12);
      osc.connect(gain).connect(ctx.destination);
      osc.start(ctx.currentTime + offset);
      osc.stop(ctx.currentTime + offset + 0.12);
    });
  } catch {}
}

export function CurrentPlayerSpotlight({ player, teams, fullscreen }: Props) {
  const [timerSeconds, setTimerSeconds] = useState(10);
  const [timerRunning, setTimerRunning] = useState(false);
  const [lastBid, setLastBid] = useState<number | null>(null);

  const currentBid = (player as any)?.current_bid as number | null;

  // Server-timestamp based timer sync
  const timerStartedAt = (player as any)?.timer_started_at as string | null;

  useEffect(() => {
    if (!timerStartedAt) { setTimerRunning(false); setTimerSeconds(10); return; }
    const elapsed = Math.floor((Date.now() - new Date(timerStartedAt).getTime()) / 1000);
    const remaining = Math.max(0, 10 - elapsed);
    setTimerSeconds(remaining);
    setTimerRunning(remaining > 0);
  }, [timerStartedAt, player?.id]);

  // Fallback: auto-start timer when bid changes (no server timestamp)
  useEffect(() => {
    if (!player || !currentBid) return;
    if (lastBid !== null && currentBid !== lastBid && !timerStartedAt) {
      setTimerSeconds(10); setTimerRunning(true);
    }
    setLastBid(currentBid);
  }, [currentBid, player, timerStartedAt]);

  // Reset timer when player changes
  useEffect(() => {
    setTimerSeconds(10); setTimerRunning(false); setLastBid(null);
  }, [player?.id]);

  // Countdown logic
  useEffect(() => {
    if (!timerRunning) return;
    const interval = setInterval(() => {
      setTimerSeconds(prev => {
        if (prev <= 1) {
          setTimerRunning(false);
          playTimerEndSound();
          return 0;
        }
        if (prev <= 4) playTickSound();
        return prev - 1;
      });
    }, 1000);
    return () => clearInterval(interval);
  }, [timerRunning]);

  if (!player) return null;

  const imageUrl = (player as any).image_url as string | null;
  const hasImage = imageUrl && imageUrl !== 'none';
  const basePriceInCr = player.base_price >= 100
    ? `Γé╣${(player.base_price / 100).toFixed(2)} Cr`
    : `Γé╣${player.base_price} L`;

  const leadingTeamId = (player as any).leading_team_id as string | null;
  const leadingTeam = teams?.find(t => t.id === leadingTeamId);

  const currentBidDisplay = currentBid
    ? `Γé╣${currentBid.toFixed(2)} Cr`
    : basePriceInCr;

  const isUrgent = timerSeconds <= 3 && timerSeconds > 0;
  const isExpired = timerSeconds === 0;

  return (
    <motion.div
      initial={{ opacity: 0, scale: 0.95 }}
      animate={{ opacity: 1, scale: 1 }}
      className={`rounded-xl border-2 border-live/50 bg-card relative overflow-hidden ${
        fullscreen ? 'min-h-[60vh]' : 'min-h-[200px]'
      }`}
    >
      {/* Animated border glow */}
      <div className="absolute inset-0 rounded-xl border-2 border-live/30 live-pulse pointer-events-none" />

      <div className={`flex flex-col justify-center h-full ${
        fullscreen ? 'p-10 md:p-16 min-h-[60vh]' : 'p-6 md:p-8'
      }`}>
        {/* Top row */}
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2">
            <span className={`rounded-full bg-live live-pulse ${fullscreen ? 'w-4 h-4' : 'w-3 h-3'}`} />
            <span className={`font-bold text-live uppercase tracking-wider ${fullscreen ? 'text-lg' : 'text-sm'}`}>
              Live ΓÇö Now Auctioning
            </span>
          </div>
          <div className="flex items-center gap-4">
            <span className={`text-muted-foreground ${fullscreen ? 'text-base' : 'text-sm'}`}>
              Set {player.set_name || player.set_number}
            </span>
            {/* Timer Display */}
            <div className={`font-display font-bold rounded-lg px-4 py-2 ${
              isExpired ? 'bg-destructive/20 text-destructive' :
              isUrgent ? 'bg-live/20 text-live live-pulse' :
              'bg-muted/50 text-foreground'
            } ${fullscreen ? 'text-3xl' : 'text-xl'}`}>
              {isExpired ? 'ΓÅ░ TIME!' : `${timerSeconds}s`}
            </div>
          </div>
        </div>

        {/* Timer progress bar */}
        <div className="mt-3 h-2 bg-muted rounded-full overflow-hidden">
          <div
            className={`h-full rounded-full transition-all duration-1000 ${
              isUrgent ? 'bg-live' : isExpired ? 'bg-destructive' : 'bg-primary'
            }`}
            style={{ width: `${(timerSeconds / 10) * 100}%` }}
          />
        </div>

        {/* Main content */}
        <div className="mt-6 flex flex-col md:flex-row md:items-end justify-between gap-6 flex-1">
          <div className="flex items-center gap-6">
            {hasImage && (
              <img
                src={imageUrl}
                alt={player.player_name}
                className={`rounded-xl object-cover border-2 border-border/50 ${
                  fullscreen ? 'w-40 h-40 md:w-52 md:h-52' : 'w-20 h-20'
                }`}
              />
            )}
            <div>
              <h2 className={`font-display font-bold text-foreground ${
                fullscreen ? 'text-6xl md:text-8xl' : 'text-4xl md:text-5xl'
              }`}>
                {player.player_name}
              </h2>
              <div className={`flex items-center gap-3 mt-3 text-muted-foreground flex-wrap ${
                fullscreen ? 'text-lg' : 'text-sm'
              }`}>
                <span className="font-medium text-foreground/80">{player.role}</span>
                <span>ΓÇó</span>
                <span>{player.country}</span>
                {player.age && (
                  <>
                    <span>ΓÇó</span>
                    <span>Age {player.age}</span>
                  </>
                )}
                {player.ipl_caps ? (
                  <>
                    <span>ΓÇó</span>
                    <span>{player.ipl_caps} IPL Caps</span>
                  </>
                ) : null}
              </div>
            </div>
          </div>

          <div className="flex items-end gap-8">
            {/* Base Price */}
            <div className="text-right">
              <div className={`text-muted-foreground ${fullscreen ? 'text-sm' : 'text-xs'}`}>Base Price</div>
              <div className={`font-display font-bold text-primary ${fullscreen ? 'text-2xl' : 'text-lg'}`}>
                {basePriceInCr}
              </div>
            </div>

            {/* Current Bid */}
            <div className="text-right">
              <div className={`text-muted-foreground ${fullscreen ? 'text-sm' : 'text-xs'}`}>Current Bid</div>
              <div className={`font-display font-bold text-live ${
                fullscreen ? 'text-5xl md:text-7xl' : 'text-3xl md:text-4xl'
              }`}>
