import { useState, useRef, useEffect } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Switch } from '@/components/ui/switch';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { useToast } from '@/hooks/use-toast';
import { Loader2, Upload, X } from 'lucide-react';
import type { Database } from '@/integrations/supabase/types';

type AuctionPlayer = Database['public']['Tables']['auction_players']['Row'];

interface Props {
  player: AuctionPlayer;
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onUpdated: () => void;
}

export function EditPlayerModal({ player, open, onOpenChange, onUpdated }: Props) {
  const { toast } = useToast();
  const [loading, setLoading] = useState(false);
  const [imageFile, setImageFile] = useState<File | null>(null);
  const [imagePreview, setImagePreview] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [form, setForm] = useState({
    player_name: '',
    country: '',
    age: '',
    role: '',
    batting_style: '',
    bowling_style: '',
    base_price: '',
    set_number: '',
    set_name: '',
    ipl_caps: '',
    is_capped: false,
  });

  useEffect(() => {
    if (open && player) {
      setForm({
        player_name: player.player_name,
        country: player.country || 'India',
        age: player.age != null ? String(player.age) : '',
        role: player.role || '',
        batting_style: player.batting_style || '',
        bowling_style: player.bowling_style || '',
        base_price: String(player.base_price),
        set_number: player.set_number != null ? String(player.set_number) : '',
        set_name: player.set_name || '',
        ipl_caps: player.ipl_caps != null ? String(player.ipl_caps) : '',
        is_capped: player.is_capped ?? false,
      });
      setImagePreview(player.image_url || null);
      setImageFile(null);
    }
  }, [open, player]);

  const update = (key: string, value: any) => setForm(f => ({ ...f, [key]: value }));

  const handleImageSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    if (file.size > 5 * 1024 * 1024) {
      toast({ title: 'Image must be under 5MB', variant: 'destructive' });
      return;
    }
    setImageFile(file);
    setImagePreview(URL.createObjectURL(file));
  };

  const clearImage = () => {
    setImageFile(null);
    setImagePreview(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const uploadImage = async (playerName: string): Promise<string | null> => {
    if (!imageFile) return null;
    const ext = imageFile.name.split('.').pop() || 'jpg';
    const path = `${Date.now()}-${playerName.replace(/\s+/g, '_')}.${ext}`;
    const { error } = await supabase.storage.from('player-images').upload(path, imageFile);
    if (error) {
      console.error('Upload error:', error);
      return null;
    }
    const { data } = supabase.storage.from('player-images').getPublicUrl(path);
    return data.publicUrl;
  };

  const handleSubmit = async () => {
    if (!form.player_name.trim()) {
      toast({ title: 'Player name is required', variant: 'destructive' });
      return;
    }
    setLoading(true);
    try {
      let imageUrl: string | null | undefined = undefined;
      if (imageFile) {
        imageUrl = await uploadImage(form.player_name.trim());
      } else if (!imagePreview) {
        imageUrl = null; // cleared
      }

      const payload: Record<string, any> = {
        player_name: form.player_name.trim(),
        country: form.country || 'India',
        age: form.age ? parseInt(form.age) : null,
        role: form.role || null,
        batting_style: form.batting_style || null,
        bowling_style: form.bowling_style || null,
        base_price: parseInt(form.base_price) || player.base_price,
        set_number: form.set_number ? parseInt(form.set_number) : null,
        set_name: form.set_name || null,
        ipl_caps: form.ipl_caps ? parseInt(form.ipl_caps) : 0,
        is_capped: form.is_capped,
      };
      if (imageUrl !== undefined) payload.image_url = imageUrl;

      const { error } = await supabase.from('auction_players').update(payload).eq('id', player.id);
      if (error) {
        toast({ title: 'Failed to update', description: error.message, variant: 'destructive' });
        return;
      }
      toast({ title: `Γ£à ${form.player_name} updated` });
      onOpenChange(false);
      onUpdated();
    } catch (err: any) {
      toast({ title: 'Error', description: err?.message, variant: 'destructive' });
    } finally {
      setLoading(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-md max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle className="font-display">Edit Player</DialogTitle>
        </DialogHeader>
        <div className="space-y-3">
          {/* Photo */}
          <div>
            <label className="text-xs text-muted-foreground">Player Photo</label>
            <div className="mt-1">
              {imagePreview ? (
                <div className="relative w-24 h-24">
                  <img src={imagePreview} alt="Preview" className="w-24 h-24 rounded-lg object-cover border border-border" />
                  <button type="button" onClick={clearImage} className="absolute -top-2 -right-2 w-5 h-5 rounded-full bg-destructive text-destructive-foreground flex items-center justify-center">
                    <X className="w-3 h-3" />
                  </button>
                </div>
              ) : (
                <button type="button" onClick={() => fileInputRef.current?.click()} className="w-24 h-24 rounded-lg border-2 border-dashed border-border hover:border-primary/50 flex flex-col items-center justify-center gap-1 text-muted-foreground hover:text-primary transition-colors">
                  <Upload className="w-5 h-5" />
                  <span className="text-[10px]">Upload</span>
                </button>
              )}
              <input ref={fileInputRef} type="file" accept="image/*" onChange={handleImageSelect} className="hidden" />
            </div>
          </div>
          <div>
            <label className="text-xs text-muted-foreground">Player Name *</label>
            <Input value={form.player_name} onChange={e => update('player_name', e.target.value)} className="h-8 text-sm" />
          </div>
          <div className="grid grid-cols-2 gap-2">
            <div>
              <label className="text-xs text-muted-foreground">Country</label>
              <Input value={form.country} onChange={e => update('country', e.target.value)} className="h-8 text-sm" />
            </div>
            <div>
              <label className="text-xs text-muted-foreground">Age</label>
              <Input type="number" value={form.age} onChange={e => update('age', e.target.value)} className="h-8 text-sm" />
            </div>
          </div>
          <div className="grid grid-cols-2 gap-2">
            <div>
              <label className="text-xs text-muted-foreground">Role</label>
              <Select value={form.role} onValueChange={v => update('role', v)}>
                <SelectTrigger className="h-8 text-xs"><SelectValue placeholder="Select role" /></SelectTrigger>
                <SelectContent>
                  <SelectItem value="Batter">Batter</SelectItem>
                  <SelectItem value="WK-Batter">WK-Batter</SelectItem>
                  <SelectItem value="All-Rounder">All-Rounder</SelectItem>
                  <SelectItem value="Fast Bowler">Fast Bowler</SelectItem>
                  <SelectItem value="Spin Bowler">Spin Bowler</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div>
              <label className="text-xs text-muted-foreground">Base Price (Γé╣ Lakh)</label>
              <Input type="number" value={form.base_price} onChange={e => update('base_price', e.target.value)} className="h-8 text-sm" />
            </div>
          </div>
          <div className="grid grid-cols-2 gap-2">
            <div>
              <label className="text-xs text-muted-foreground">Batting Style</label>
              <Input value={form.batting_style} onChange={e => update('batting_style', e.target.value)} className="h-8 text-sm" />
            </div>
            <div>
              <label className="text-xs text-muted-foreground">Bowling Style</label>
              <Input value={form.bowling_style} onChange={e => update('bowling_style', e.target.value)} className="h-8 text-sm" />
            </div>
          </div>
          <div className="grid grid-cols-2 gap-2">
            <div>
              <label className="text-xs text-muted-foreground">Set Number</label>
              <Input type="number" value={form.set_number} onChange={e => update('set_number', e.target.value)} className="h-8 text-sm" />
            </div>
            <div>
              <label className="text-xs text-muted-foreground">Set Name</label>
              <Input value={form.set_name} onChange={e => update('set_name', e.target.value)} className="h-8 text-sm" />
            </div>
          </div>
          <div className="grid grid-cols-2 gap-2">
            <div>
              <label className="text-xs text-muted-foreground">IPL Caps</label>
              <Input type="number" value={form.ipl_caps} onChange={e => update('ipl_caps', e.target.value)} className="h-8 text-sm" />
            </div>
            <div className="flex items-center gap-2 mt-4">
              <Switch checked={form.is_capped} onCheckedChange={v => update('is_capped', v)} />
              <label className="text-xs text-muted-foreground">Capped Player</label>
            </div>
          </div>
          <div className="flex gap-2 pt-2">
            <Button onClick={handleSubmit} className="flex-1" disabled={loading}>
              {loading && <Loader2 className="w-3 h-3 mr-1 animate-spin" />}
              Save Changes
            </Button>
            <Button variant="outline" onClick={() => onOpenChange(false)} className="flex-1">Cancel</Button>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}

import { useState } from 'react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Shuffle, CheckCircle2, Loader2, Users } from 'lucide-react';
import { supabase } from '@/integrations/supabase/client';
import { useToast } from '@/hooks/use-toast';
import type { Database } from '@/integrations/supabase/types';

type Team = Database['public']['Tables']['teams']['Row'];

interface Props {
  teams: Team[];
  onSaved?: () => void;
}

interface Assignment { name: string; team: Team }

export function RandomTeamGenerator({ teams, onSaved }: Props) {
  const { toast } = useToast();
  const [open, setOpen] = useState(false);
  const [namesInput, setNamesInput] = useState('');
  const [assignments, setAssignments] = useState<Assignment[]>([]);
  const [saving, setSaving] = useState(false);
  const [saved, setSaved] = useState(false);

  const generate = () => {
    const names = namesInput.split(',').map(n => n.trim()).filter(Boolean);
    if (!names.length) {
      toast({ title: 'Enter at least one name', variant: 'destructive' });
      return;
    }
    const shuffled = [...teams].sort(() => Math.random() - 0.5);
    setAssignments(names.map((name, i) => ({ name, team: shuffled[i % shuffled.length] })));
    setSaved(false);
  };

  const confirmAndSave = async () => {
    if (!assignments.length) return;
    setSaving(true);

    try {
      // Step 1: Clear all existing owner names from every team
      const clearAll = teams.map(t =>
        supabase.from('teams').update({ owner_name: null }).eq('id', t.id)
      );
      await Promise.all(clearAll);

      // Step 2: Group names per team (multiple people can share a team)
      const teamOwners: Record<string, string[]> = {};
      assignments.forEach(a => {
        if (!teamOwners[a.team.id]) teamOwners[a.team.id] = [];
        teamOwners[a.team.id].push(a.name);
      });

      // Step 3: Update each team's owner_name (uses existing UPDATE policy)
      const updates = Object.entries(teamOwners).map(([teamId, names]) =>
        supabase
          .from('teams')
          .update({ owner_name: names.join(', ') })
          .eq('id', teamId)
      );
      const results = await Promise.all(updates);

      const failed = results.find(r => r.error);
      if (failed?.error) throw new Error(failed.error.message);

      setSaved(true);
      toast({
        title: 'Γ£à Teams assigned!',
        description: `${assignments.length} participants assigned and visible on team cards.`,
      });
      onSaved?.();
    } catch (e: any) {
      toast({
        title: 'Failed to save',
        description: e.message || 'Unknown error',
        variant: 'destructive',
      });
    } finally {
      setSaving(false);
    }
  };

  const handleClose = () => {
    setOpen(false);
    setAssignments([]);
    setSaved(false);
  };

  if (!open) {
    return (
      <Button variant="outline" size="sm" className="text-xs gap-1.5" onClick={() => setOpen(true)}>
        <Shuffle className="w-3.5 h-3.5" /> Random Team Generator
      </Button>
    );
  }

  return (
    <div className="bg-card border border-border rounded-lg p-4 space-y-3">
      <div className="flex items-center justify-between">
        <h3 className="font-display font-bold text-sm flex items-center gap-1.5">
          <Users className="w-4 h-4" /> Random Team Generator
        </h3>
        <Button variant="ghost" size="sm" className="h-6 w-6 p-0" onClick={handleClose}>Γ£ò</Button>
      </div>

      <div>
        <label className="text-xs text-muted-foreground mb-1 block">
          Participant names <span className="opacity-60">(comma-separated)</span>
        </label>
        <Input
          placeholder="Benadict, Avinash, Dhanush, Harsha..."
          value={namesInput}
          onChange={e => { setNamesInput(e.target.value); setSaved(false); }}
          className="h-8 text-xs"
          onKeyDown={e => e.key === 'Enter' && generate()}
        />
      </div>

      <Button size="sm" onClick={generate} className="w-full gap-1.5" disabled={!namesInput.trim() || saving}>
        <Shuffle className="w-3.5 h-3.5" /> Generate Teams
      </Button>

      {assignments.length > 0 && (
        <div className="space-y-2">
          <div className="flex items-center justify-between">
            <span className="text-xs font-bold text-muted-foreground uppercase tracking-wider">Assignments</span>
            <span className="text-[10px] bg-muted px-1.5 py-0.5 rounded text-muted-foreground">{assignments.length} people</span>
          </div>

          <div className="max-h-52 overflow-y-auto space-y-1 pr-1 scrollbar-thin">
            {assignments.map((a, i) => (
              <div key={i} className="flex items-center justify-between text-sm py-1.5 px-2.5 rounded-lg bg-muted/40 border border-border/30">
                <span className="font-medium text-foreground truncate pr-2">{a.name}</span>
                <div className="flex items-center gap-1.5 shrink-0">
                  {a.team.logo_url && (
                    <img src={a.team.logo_url} alt="" className="w-4 h-4 object-contain" />
                  )}
                  <span
                    className="font-display font-bold text-[11px] px-2 py-0.5 rounded"
                    style={{ backgroundColor: a.team.color, color: '#fff' }}
                  >
                    {a.team.short_name}
                  </span>
                </div>
              </div>
            ))}
          </div>

          {!saved ? (
            <Button onClick={confirmAndSave} disabled={saving} className="w-full gap-2" size="sm">
              {saving
                ? <><Loader2 className="w-3.5 h-3.5 animate-spin" /> SavingΓÇª</>
                : <>Γ£à Confirm ΓÇö Show on Team Overview</>
              }
            </Button>
          ) : (
            <div className="flex items-center gap-2 text-xs text-emerald-500 font-semibold justify-center py-2 rounded-lg bg-emerald-500/10 border border-emerald-500/20">
              <CheckCircle2 className="w-4 h-4" /> Saved! Visible on all team cards now.
            </div>
          )}

          <Button variant="ghost" size="sm" className="w-full text-xs gap-1" onClick={generate} disabled={saving}>
            <Shuffle className="w-3 h-3" /> Shuffle Again
          </Button>
        </div>
      )}
    </div>
  );
}

import * as React from "react";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

const badgeVariants = cva(
  "inline-flex items-center rounded-full border px-2.5 py-0.5 text-xs font-semibold transition-colors focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2",
  {
    variants: {
      variant: {
        default: "border-transparent bg-primary text-primary-foreground hover:bg-primary/80",
        secondary: "border-transparent bg-secondary text-secondary-foreground hover:bg-secondary/80",
        destructive: "border-transparent bg-destructive text-destructive-foreground hover:bg-destructive/80",
        outline: "text-foreground",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  },
);

export interface BadgeProps extends React.HTMLAttributes<HTMLDivElement>, VariantProps<typeof badgeVariants> {}

function Badge({ className, variant, ...props }: BadgeProps) {
  return <div className={cn(badgeVariants({ variant }), className)} {...props} />;
}

export { Badge, badgeVariants };

