import { BidTracker } from '@/components/BidTracker';
import { AddPlayerModal } from '@/components/AddPlayerModal';
import { EditPlayerModal } from '@/components/EditPlayerModal';
import { AcceleratedAuction } from '@/components/AcceleratedAuction';
import { RandomTeamGenerator } from '@/components/RandomTeamGenerator';
import { Pencil, Trash2 } from 'lucide-react';
import type { Database } from '@/integrations/supabase/types';

type AuctionPlayer = Database['public']['Tables']['auction_players']['Row'];

const PASSCODE = 'IPL2026';

export default function HostPanel() {
  const [authenticated, setAuthenticated] = useState(() => {
    return localStorage.getItem('host_auth') === 'true';
  });
  const [passcode, setPasscode] = useState('');
  const { toast } = useToast();

  if (!authenticated) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="bg-card border border-border rounded-lg p-8 w-full max-w-sm">
          <h1 className="font-display font-bold text-2xl text-foreground mb-4 text-center">Host Login</h1>
          <p className="text-sm text-muted-foreground mb-4 text-center">Enter the auction passcode</p>
          <form onSubmit={(e) => {
            e.preventDefault();
            if (passcode === PASSCODE) {
              localStorage.setItem('host_auth', 'true');
              setAuthenticated(true);
            } else {
              toast({ title: 'Wrong passcode', variant: 'destructive' });
            }
          }}>
            <Input
              type="password"
              value={passcode}
              onChange={e => setPasscode(e.target.value)}
              placeholder="Enter passcode"
              className="mb-4"
            />
            <Button type="submit" className="w-full">Enter Auction Room</Button>
          </form>
        </div>
      </div>
    );
  }

  return <HostDashboard />;
}

function HostDashboard() {
  const {
    teams,
    auctionPlayers,
    currentPlayer,
    auctionLog,
    refetch,
    soldPlayersByTeam,
  } = useAuctionData();
  const { toast } = useToast();

  const [search, setSearch] = useState('');
  const [filterRole, setFilterRole] = useState('all');
  const [filterStatus, setFilterStatus] = useState('all');
  const [filterSet, setFilterSet] = useState('all');
  const [editPlayer, setEditPlayer] = useState<AuctionPlayer | null>(null);
  const [deleteConfirm, setDeleteConfirm] = useState<AuctionPlayer | null>(null);

  const setNumbers = useMemo(() => {
    const sets = new Map<number, { name: string; count: number }>();
    auctionPlayers.forEach(p => {
      const num = p.set_number ?? -1;
      if (!sets.has(num)) {
        sets.set(num, { name: p.set_name || `Set ${num}`, count: 0 });
      }
      sets.get(num)!.count++;
    });
    return Array.from(sets.entries()).sort((a, b) => a[0] - b[0]);
  }, [auctionPlayers]);

  const filteredPlayers = useMemo(() => {
    return auctionPlayers.filter(p => {
      const matchSearch = !search || p.player_name.toLowerCase().includes(search.toLowerCase());
      const matchRole = filterRole === 'all' || p.role === filterRole;
      const matchStatus = filterStatus === 'all' || p.status === filterStatus;
      const matchSet = filterSet === 'all' || String(p.set_number) === filterSet;
      return matchSearch && matchRole && matchStatus && matchSet;
    }).slice(0, 100);
  }, [auctionPlayers, search, filterRole, filterStatus, filterSet]);

  // Get unique roles from the dataset
  const uniqueRoles = useMemo(() => {
    const roles = new Set<string>();
    auctionPlayers.forEach(p => { if (p.role) roles.add(p.role); });
    return Array.from(roles).sort();
  }, [auctionPlayers]);

  const setAsCurrent = async (playerId: string) => {
    await supabase.from('auction_players').update({ status: 'available', current_bid: null, leading_team_id: null, timer_started_at: null } as any).eq('status', 'current');
    const player = auctionPlayers.find(p => p.id === playerId);
    const baseCr = player ? player.base_price / 100 : 0;
    await supabase.from('auction_players').update({ status: 'current', current_bid: baseCr, leading_team_id: null, timer_started_at: null } as any).eq('id', playerId);
    toast({ title: 'Player set as current' });
    refetch();
  };

  const undoLastSale = async () => {
    if (auctionLog.length === 0) return;
    const last = auctionLog[0];

    if (last.action === 'unsold') {
      await supabase.from('auction_log').delete().eq('id', last.id);
      if (last.player_id) {
        await supabase.from('auction_players').update({ status: 'available', current_bid: null, leading_team_id: null } as any).eq('id', last.player_id);
      }
      toast({ title: `Undo: ${last.player_name} set back to available` });
      refetch();
      return;
    }

    if (last.action === 'sold') {
      if (last.player_id) {
        await supabase.from('auction_players').update({
          status: 'available',
          sold_to_team: null,
          sold_price: null,
          current_bid: null,
          leading_team_id: null,
        } as any).eq('id', last.player_id);
      }
      if (last.team_id && last.sold_price) {
        const team = teams.find(t => t.id === last.team_id);
        if (team) {
          await supabase.from('teams').update({
            spent_budget: Math.max(0, team.spent_budget - last.sold_price),
          }).eq('id', last.team_id);
        }
      }
    } else {
      if (last.player_id) {
        await supabase.from('auction_players').update({ status: 'available', current_bid: null, leading_team_id: null } as any).eq('id', last.player_id);
      }
    }

    await supabase.from('auction_log').delete().eq('id', last.id);
    toast({ title: `Undid: ${last.player_name} (${last.action})` });
    refetch();
  };

  const [showRestartConfirm, setShowRestartConfirm] = useState(false);

  const restartAuction = async () => {
    await supabase.from('auction_players').update({
      status: 'available',
      sold_to_team: null,
      sold_price: null,
      current_bid: null,
      leading_team_id: null,
    } as any).neq('status', 'available');
    await supabase.from('teams').update({ spent_budget: 0 }).gt('spent_budget', 0);
    await supabase.from('auction_log').delete().gte('created_at', '2000-01-01');
    setShowRestartConfirm(false);
    toast({ title: 'Auction restarted! All data has been reset.' });
    refetch();
  };

  return (
    <div className="min-h-screen p-4 max-w-[1400px] mx-auto">
      {/* Header */}
      <div className="flex items-center justify-between mb-4">
        <div>
          <h1 className="font-display font-bold text-2xl text-foreground">Auctioneer Control Panel</h1>
          <p className="text-xs text-muted-foreground">Manage the live auction</p>
        </div>
        <div className="flex gap-2 flex-wrap">
          <Link to="/">
            <Button variant="outline" size="sm" className="text-xs">View Dashboard</Button>
          </Link>
          <Button variant="destructive" size="sm" className="text-xs" onClick={undoLastSale}>
            Γå⌐ Undo Last
          </Button>
          <Button variant="outline" size="sm" className="text-xs border-destructive text-destructive hover:bg-destructive hover:text-destructive-foreground" onClick={() => setShowRestartConfirm(true)}>
            ≡ƒöä Restart Auction
          </Button>
        </div>
      </div>

      {/* Restart Confirmation Dialog */}
      {showRestartConfirm && (
        <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4">
          <div className="bg-card border border-border rounded-lg p-6 max-w-sm w-full space-y-4">
            <h2 className="font-display font-bold text-lg text-foreground">ΓÜá∩╕Å Restart Auction?</h2>
            <p className="text-sm text-muted-foreground">
              This will reset <strong>all players</strong> to available, clear <strong>all sales</strong>, reset <strong>all team budgets</strong>, and delete the <strong>auction log</strong>. This cannot be undone.
            </p>
            <div className="flex gap-2">
              <Button variant="destructive" className="flex-1" onClick={restartAuction}>Yes, Restart</Button>
              <Button variant="outline" className="flex-1" onClick={() => setShowRestartConfirm(false)}>Cancel</Button>
            </div>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
        {/* Left: Bid Tracker + Accelerated Auction + Team Budgets */}
        <div className="lg:col-span-1 space-y-4">
          {currentPlayer ? (
            <BidTracker currentPlayer={currentPlayer} teams={teams} onComplete={refetch} />
          ) : (
            <div className="bg-card border border-border rounded-lg p-4 text-center text-sm text-muted-foreground">
              No player currently being auctioned. Select one from the player list.
            </div>
          )}

          {/* Accelerated Auction */}
          <AcceleratedAuction auctionPlayers={auctionPlayers} onComplete={refetch} />

          {/* Random Team Generator */}
          <RandomTeamGenerator teams={teams} onSaved={refetch} />

          {/* Team Budget Monitor */}
          <div className="bg-card border border-border rounded-lg p-3">
            <h3 className="font-display font-bold text-sm mb-2">Team Budgets</h3>
            <div className="space-y-1">
              {teams.map(t => {
                const remaining = t.total_budget - t.spent_budget;
                const sold = soldPlayersByTeam(t.id);
                return (
                  <div key={t.id} className="flex items-center justify-between text-xs py-1">
                    <div className="flex items-center gap-1.5">
                      <span className="w-2 h-2 rounded-full" style={{ backgroundColor: t.color }} />
                      <span className="font-medium">{t.short_name}</span>
                      <span className="text-muted-foreground">({sold.length}/{t.player_slots})</span>
                    </div>
                    <span style={{ color: t.color }} className="font-medium">Γé╣{remaining.toFixed(2)} Cr</span>
                  </div>
                );
              })}
            </div>
          </div>
        </div>

        {/* Right: Player Browser */}
        <div className="lg:col-span-2">
          <div className="bg-card border border-border rounded-lg">
            <div className="p-3 border-b border-border">
              <div className="flex items-center justify-between mb-2">
                <div className="flex items-center gap-2">
                  <h3 className="font-display font-bold text-sm">Player Browser</h3>
                  <span className="text-[10px] text-muted-foreground bg-muted px-1.5 py-0.5 rounded">
                    {auctionPlayers.length} players ┬╖ {filteredPlayers.length} shown
                  </span>
                </div>
                <AddPlayerModal onAdded={refetch} />
              </div>
              <div className="flex gap-2 flex-wrap">
                <Input
                  placeholder="Search player..."
                  value={search}
                  onChange={e => setSearch(e.target.value)}
                  className="flex-1 min-w-[150px] h-8 text-xs"
                />
                <Select value={filterSet} onValueChange={setFilterSet}>
                  <SelectTrigger className="w-[160px] h-8 text-xs"><SelectValue /></SelectTrigger>
                  <SelectContent className="max-h-[300px]">
                    <SelectItem value="all">All Sets</SelectItem>
                    {setNumbers.map(([num, { name, count }]) => (
                      <SelectItem key={num} value={String(num)}>{name} ({count})</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
                <Select value={filterRole} onValueChange={setFilterRole}>
                  <SelectTrigger className="w-[130px] h-8 text-xs"><SelectValue /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="all">All Roles</SelectItem>
                    {uniqueRoles.map(role => (
                      <SelectItem key={role} value={role}>{role}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
                <Select value={filterStatus} onValueChange={setFilterStatus}>
                  <SelectTrigger className="w-[120px] h-8 text-xs"><SelectValue /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="all">All Status</SelectItem>
                    <SelectItem value="available">Available</SelectItem>
                    <SelectItem value="sold">Sold</SelectItem>
                    <SelectItem value="unsold">Unsold</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </div>
            <div className="overflow-x-auto max-h-[500px] overflow-y-auto scrollbar-thin">
              <table className="w-full text-xs">
                <thead className="sticky top-0 bg-card">
                  <tr className="border-b border-border text-muted-foreground">
                    <th className="text-left p-2">Set</th>
                    <th className="text-left p-2">Player</th>
                    <th className="text-left p-2">Country</th>
                    <th className="text-left p-2">Role</th>
                    <th className="text-right p-2">Base</th>
                    <th className="text-center p-2">Status</th>
                    <th className="text-center p-2">Action</th>
                    <th className="text-center p-2">Update</th>
                    <th className="text-center p-2">Delete</th>
                  </tr>
                </thead>
                <tbody>
                  {filteredPlayers.map(p => (
                    <tr key={p.id} className="border-b border-border/30 hover:bg-muted/20">
                      <td className="p-2">{p.set_name || p.set_number}</td>
                      <td className="p-2 font-medium">{p.player_name}</td>
                      <td className="p-2">{p.country}</td>
                      <td className="p-2">{p.role}</td>
                      <td className="p-2 text-right">Γé╣{p.base_price}L</td>
                      <td className="p-2 text-center">
                        <span className={`px-1.5 py-0.5 rounded text-[10px] font-medium ${
                          p.status === 'available' ? 'bg-primary/20 text-primary' :
                          p.status === 'sold' ? 'bg-sold/20 text-sold' :
                          p.status === 'current' ? 'bg-live/20 text-live' :
                          'bg-unsold/20 text-unsold'
                        }`}>
                          {p.status}
                        </span>
                      </td>
                      <td className="p-2 text-center">
                        {(p.status === 'available' || p.status === 'unsold') && (
                          <Button size="sm" variant="ghost" className="h-6 text-[10px] px-2" onClick={() => setAsCurrent(p.id)}>
                            Set Current
                          </Button>
                        )}
                      </td>
                      <td className="p-2 text-center">
                        <Button size="sm" variant="ghost" className="h-6 w-6 p-0" onClick={() => setEditPlayer(p)}>
                          <Pencil className="w-3 h-3" />
                        </Button>
                      </td>
                      <td className="p-2 text-center">
                        <Button size="sm" variant="ghost" className="h-6 w-6 p-0 text-destructive hover:text-destructive" onClick={() => setDeleteConfirm(p)}>
                          <Trash2 className="w-3 h-3" />
                        </Button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      </div>

      {/* Edit Player Modal */}
      {editPlayer && (
        <EditPlayerModal
          player={editPlayer}
          open={!!editPlayer}
          onOpenChange={(open) => { if (!open) setEditPlayer(null); }}
          onUpdated={refetch}
        />
      )}

      {/* Delete Confirmation */}
      {deleteConfirm && (
        <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4">
          <div className="bg-card border border-border rounded-lg p-6 max-w-sm w-full space-y-4">
            <h2 className="font-display font-bold text-lg text-foreground">Delete Player?</h2>
            <p className="text-sm text-muted-foreground">
              Are you sure you want to delete <strong>{deleteConfirm.player_name}</strong>? This cannot be undone.
            </p>
            <div className="flex gap-2">
              <Button variant="destructive" className="flex-1" onClick={async () => {
                await supabase.from('auction_players').delete().eq('id', deleteConfirm.id);
                toast({ title: `≡ƒùæ∩╕Å ${deleteConfirm.player_name} deleted` });
                setDeleteConfirm(null);
                refetch();
              }}>Yes, Delete</Button>
              <Button variant="outline" className="flex-1" onClick={() => setDeleteConfirm(null)}>Cancel</Button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import { useParams, Link } from 'react-router-dom';
import { useAuctionData } from '@/hooks/useAuctionData';
import { Button } from '@/components/ui/button';
import { ArrowLeft } from 'lucide-react';
import { useMemo } from 'react';

const ROLE_CATEGORIES = [
  { label: 'BATSMEN',     keys: ['BATTER', 'BATSMAN', 'BATSMEN', 'BAT'] },
  { label: 'WK BATTER',  keys: ['WICKETKEEPER', 'WK-BATTER', 'WK BATTER', 'WICKET-KEEPER', 'WK'] },
  { label: 'ALLROUNDER', keys: ['ALL-ROUNDER', 'ALLROUNDER', 'ALL ROUNDER', 'AR'] },
  { label: 'FAST BOWLER',keys: ['FAST BOWLER', 'PACER', 'PACE', 'SEAMER', 'FAST', 'BOWLER'] },
  { label: 'SPIN BOWLER', keys: ['SPINNER', 'SPIN', 'SPIN BOWLER'] },
];

function categorizeRole(role: string | null): string {
  if (!role) return 'BATSMEN';
  const upper = role.toUpperCase().trim();
  for (const cat of ROLE_CATEGORIES) {
    if (cat.keys.some(k => upper === k || upper.includes(k))) return cat.label;
  }
  if (upper.includes('BOWL')) return 'FAST BOWLER';
  return 'BATSMEN';
}

function fmtPrice(price: number | null | undefined): string {
  if (price == null) return '';
  return `Γé╣${Math.round(price * 100) / 100}`;
}

export default function TeamDetail() {
  const { teamId } = useParams<{ teamId: string }>();
  const { teams, soldPlayersByTeam, retainedByTeam, loading } = useAuctionData();

  const team = teams.find(t => t.id === teamId);
  const retained = teamId ? retainedByTeam(teamId) : [];
  const soldPlayers = teamId ? soldPlayersByTeam(teamId) : [];

  const remaining = team ? team.total_budget - team.spent_budget : 0;
  const totalPlayers = soldPlayers.length + retained.length;
  const overseasCount =
    soldPlayers.filter(p => p.country !== 'India').length +
    retained.filter(r => r.nationality !== 'India' && r.nationality != null).length;

  const allPlayers = useMemo(() => [
    ...retained.map(p => ({
      name: p.player_name,
      price: p.retention_price,
      overseas: p.nationality !== 'India' && p.nationality != null,
      role: categorizeRole(p.role),
      isRetained: true,
    })),
    ...soldPlayers.map(p => ({
      name: p.player_name,
      price: p.sold_price,
      overseas: p.country !== 'India' && p.country != null,
      role: categorizeRole(p.role),
      isRetained: false,
    })),
  ], [retained, soldPlayers]);

  const roleGroups = useMemo(() =>
    ROLE_CATEGORIES
      .map(cat => ({
        label: cat.label,
        players: allPlayers
          .filter(p => p.role === cat.label)
          .sort((a, b) => (b.price ?? 0) - (a.price ?? 0)),
      }))
      .filter(g => g.players.length > 0),
    [allPlayers]
  );

  const topBuys = useMemo(() =>
    [...soldPlayers]
      .filter(p => p.sold_price != null)
      .sort((a, b) => (b.sold_price ?? 0) - (a.sold_price ?? 0))
      .slice(0, 5),
    [soldPlayers]
  );

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="font-display text-xl text-muted-foreground">Loading...</div>
      </div>
    );
  }

  if (!team) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-center">
          <div className="font-display text-xl text-muted-foreground mb-4">Team not found</div>
          <Link to="/"><Button variant="outline">Back to Dashboard</Button></Link>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen p-4 max-w-[1200px] mx-auto">
      <Link to="/">
        <Button variant="ghost" size="sm" className="mb-4 gap-1.5 text-xs">
          <ArrowLeft className="w-3.5 h-3.5" /> Back to Dashboard
        </Button>
      </Link>

      {/* Team Header ΓÇö matches image */}
      <div
        className="rounded-xl p-6 mb-6 border border-border/50"
        style={{
          background: `linear-gradient(135deg, ${team.color}18 0%, hsl(var(--card)) 80%)`,
          borderLeft: `5px solid ${team.color}`,
        }}
      >
        <div className="flex items-center gap-4 mb-5">
          {team.logo_url && (
            <img src={team.logo_url} alt={team.short_name} className="w-14 h-14 object-contain" />
          )}
          <div>
            <h1 className="font-display font-bold text-3xl text-foreground">{team.name}</h1>
            <span
              className="font-display font-bold text-sm px-3 py-1 rounded mt-1 inline-block"
              style={{ backgroundColor: team.color, color: '#fff' }}
            >
              {team.short_name}
            </span>
          </div>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
          {[
            { label: 'Purse Left', value: `Γé╣${remaining.toFixed(2)} Cr`, colored: true },
            { label: 'Spent',      value: `Γé╣${team.spent_budget.toFixed(2)} Cr`, colored: false },
            { label: 'Players',    value: `${totalPlayers}/${team.player_slots}`, colored: false },
            { label: 'Overseas',   value: `${overseasCount}/${team.overseas_slots}`, colored: false },
          ].map(stat => (
            <div key={stat.label} className="bg-background/60 rounded-lg p-3 text-center border border-border/30">
              <div className="text-xs text-muted-foreground mb-1">{stat.label}</div>
              <div
                className="font-display font-bold text-2xl"
                style={stat.colored ? { color: team.color } : {}}
              >
                {stat.value}
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Top Buys */}
      {topBuys.length > 0 && (
        <div className="mb-6">
          <h2 className="font-display font-bold text-lg text-foreground mb-3">Top Buys</h2>
          <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-5 gap-3">
            {topBuys.map(p => (
              <div
                key={p.id}
                className="rounded-xl border border-border/40 p-3 text-center"
                style={{ background: `${team.color}12` }}
              >
                <div className="font-bold text-sm text-foreground leading-tight">{p.player_name}</div>
                <div className="text-xs text-muted-foreground mt-0.5">{p.role}</div>
                <div className="font-display font-bold text-base mt-2" style={{ color: team.color }}>
                  {fmtPrice(p.sold_price)} Cr
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Squad Breakdown */}
      <h2 className="font-display font-bold text-lg text-foreground mb-3">Squad Breakdown</h2>
      {roleGroups.length === 0 ? (
        <div className="text-center text-muted-foreground py-12 text-sm">
          No players yet. They'll appear here once bought or retained.
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {roleGroups.map(group => (
            <div
              key={group.label}
              className="rounded-xl border border-border/40 p-4"
              style={{ background: `${team.color}08` }}
            >
              {/* Category Header */}
              <div className="flex items-center justify-between mb-3">
                <span className="text-xs font-bold uppercase tracking-wider" style={{ color: team.color }}>
                  {group.label}
                </span>
                <span
                  className="text-xs font-bold rounded px-2 py-0.5"
                  style={{ backgroundColor: `${team.color}25`, color: team.color }}
                >
                  {group.players.length}
                </span>
              </div>
              {/* Player rows */}
              <div className="space-y-2">
                {group.players.map((p, i) => (
                  <div key={i} className="flex items-center justify-between text-sm">
                    <span className="flex items-center gap-1.5 text-foreground">
                      {p.overseas && <span className="text-xs">Γ£ê∩╕Å</span>}
                      {p.name}
                      {p.isRetained && (
                        <span className="text-[10px] bg-primary/20 text-primary px-1.5 py-0.5 rounded">RTM</span>
                      )}
                    </span>
                    {p.price != null && (
                      <span className="font-bold whitespace-nowrap ml-2" style={{ color: team.color }}>
                        {fmtPrice(p.price)} Cr
                      </span>
                    )}
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

async function getWikipediaImage(playerName: string): Promise<string | null> {
  try {
    // Search for the player's Wikipedia page
    const searchUrl = `https://en.wikipedia.org/w/api.php?action=query&titles=${encodeURIComponent(playerName)}&prop=pageimages&format=json&pithumbsize=300&redirects=1`;
    const res = await fetch(searchUrl);
    const data = await res.json();
    const pages = data.query?.pages;
    if (!pages) return null;

    const page = Object.values(pages)[0] as any;
    if (page?.thumbnail?.source) {
      return page.thumbnail.source;
    }

    // Try with "(cricketer)" suffix
    const searchUrl2 = `https://en.wikipedia.org/w/api.php?action=query&titles=${encodeURIComponent(playerName + ' (cricketer)')}&prop=pageimages&format=json&pithumbsize=300&redirects=1`;
    const res2 = await fetch(searchUrl2);
    const data2 = await res2.json();
    const pages2 = data2.query?.pages;
    if (!pages2) return null;

    const page2 = Object.values(pages2)[0] as any;
    return page2?.thumbnail?.source || null;
  } catch (e) {
    console.error(`Failed to fetch image for ${playerName}:`, e);
    return null;
  }
}

Deno.serve(async (req) => {
  if (req.method === 'OPTIONS') {
    return new Response(null, { headers: corsHeaders });
  }

  try {
    const supabaseUrl = Deno.env.get('SUPABASE_URL')!;
    const serviceKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!;
    const supabase = createClient(supabaseUrl, serviceKey);

    // Get players without images
    const { data: players, error } = await supabase
      .from('auction_players')
      .select('id, player_name')
      .is('image_url', null)
      .limit(50);

    if (error) throw error;
    if (!players || players.length === 0) {
      return new Response(JSON.stringify({ success: true, message: 'No players need images', updated: 0 }),
        { headers: { ...corsHeaders, 'Content-Type': 'application/json' } });
    }

    let updated = 0;
    const results: { name: string; found: boolean }[] = [];

    for (const player of players) {
      const imageUrl = await getWikipediaImage(player.player_name);
      if (imageUrl) {
        await supabase.from('auction_players').update({ image_url: imageUrl }).eq('id', player.id);
        updated++;
        results.push({ name: player.player_name, found: true });
      } else {
        // Set a placeholder so we don't retry
        await supabase.from('auction_players').update({ image_url: 'none' }).eq('id', player.id);
        results.push({ name: player.player_name, found: false });
      }

      // Rate limit - small delay between requests
      await new Promise(r => setTimeout(r, 200));
    }

    return new Response(JSON.stringify({ success: true, updated, total: players.length, results }),
      { headers: { ...corsHeaders, 'Content-Type': 'application/json' } });
  } catch (error) {
    console.error('Error:', error);
    return new Response(JSON.stringify({ success: false, error: error.message }),
      { status: 500, headers: { ...corsHeaders, 'Content-Type': 'application/json' } });
  }
});

